import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  projectId: 'ecommerce-flowise',
});

// In Flowise chatflow config
export const onChainEnd = async (payload: any) => {
  const result = await vex.check({
    input: payload.input,
    output: payload.output,
    context: { flowType: 'ecommerce_chatflow' },
    guards: ['ftc_claims', 'pricing_accuracy'],
  });
  if (!result.pass) {
    throw new Error(`Compliance failure: ${result.issues[0].message}`);
  }
  return payload;
};

// Flowise Vector Store Node callback
const onRetrieve = async (docs: any[]) => {
  const vex = new Vex({ apiKey: process.env.VEX_API_KEY });
  const check = await vex.check({
    input: 'product pricing query',
    output: docs.map(d => d.pageContent),
    guards: ['relevance_threshold:0.8'],
    metadata: { source: 'ecommerce_catalog' },
  });
  return check.pass ? docs : [];
};

// Agent handoff interceptor
const handoffGuard = async (fromAgent: string, toAgent: string, context: any) => {
  const vex = new Vex({ apiKey: process.env.VEX_API_KEY });
  const result = await vex.check({
    input: context,
    guards: ['pii_redaction', 'context_drift'],
    policy: 'ecommerce_agent_handoff',
  });
  if (!result.pass) {
    console.warn('Blocked handoff:', result.issues);
    return null;
  }
  return context;
};
